# Dummy login for demonstration purposes
@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')

    # In a real app, verify username and password hash against the DB
    if username == 'testuser' and password == 'password123':
        user_id = 1
        session['user_id'] = user_id
        return jsonify({'message': 'Logged in successfully'}), 200
    return jsonify({'message': 'Invalid credentials'}), 401

# Dummy decorator for authentication
def login_required(f):
    def wrapper(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'message': 'Authentication required'}), 401
        return f(*args, **kwargs)
    wrapper.__name__ = f.__name__ # Preserve original function name
    return wrapper

@app.route('/profile', methods=['POST'])
@login_required
def update_profile():
    user_id = session['user_id']
    user = users_db.get(user_id)

    if not user:
        # This case should ideally not happen if session['user_id'] is valid
        return jsonify({'message': 'User not found'}), 404

    data = request.get_json()

    # Update email
    new_email = data.get('email')
    if new_email:
        # Add email validation here (e.g., regex, uniqueness check)
        user['email'] = new_email
        # In a real app, save to database
        print(f"User {user_id} email updated to: {new_email}")

    # Update password
    new_password = data.get('password')
    if new_password:
        # Add password validation here (e.g., strength requirements)
        # In a real app, hash the new_password before storing
        user['password_hash'] = f'new_hashed_password_{new_password}'
        # In a real app, save to database
        print(f"User {user_id} password updated.")

    # Update 2FA settings
    # For simplicity, we'll just toggle the '2fa_enabled' flag
    # A real 2FA setup would involve generating/verifying secrets
    new_2fa_status = data.get('2fa_enabled')
    if new_2fa_status is not None: # Check if the key exists in the payload
        if isinstance(new_2fa_status, bool):
            user['2fa_enabled'] = new_2fa_status
            if new_2fa_status and not user['2fa_secret']:
                # In a real app, generate a new 2FA secret here
                user['2fa_secret'] = 'new_2fa_secret_example'
                print(f"User {user_id} 2FA enabled and new secret generated.")
            elif not new_2fa_status:
                # Optionally, clear the 2FA secret if 2FA is disabled
                user['2fa_secret'] = None
                print(f"User {user_id} 2FA disabled.")
            # In a real app, save to database
        else:
            return jsonify({'message': '2FA enabled status must be a boolean'}), 400

    # If no valid update fields were provided, respond accordingly
    if not (new_email or new_password or (new_2fa_status is not None)):
        return jsonify({'message': 'No valid profile fields provided for update'}), 400

    return jsonify({'message': 'Profile updated successfully', 'user': user}), 200

